'use client';

import React, { useState, useEffect, useMemo } from 'react';
import { getUsers, saveUsers } from '@/lib/store';
import { User } from '@/lib/types';
import { 
  Search, Users as UsersIcon, Ban, UserCheck, MoreHorizontal, FileText, Filter, UsersRound, 
  ChevronLeft, ChevronRight, Eye, EyeOff, Pencil, Trash2, CheckCircle2, ShieldAlert, 
  Calendar, ShieldCheck, Clock, FileBadge, AlertTriangle, Shield
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { toast } from '@/hooks/use-toast';
import { cn } from '@/lib/utils';

// Unified Card component with theme support
const Card = ({ title, value, change, icon, accent }: any) => {
    const accentClasses = {
        green: 'bg-gradient-to-br from-green-400 to-green-600',
        blue: 'bg-gradient-to-br from-blue-400 to-blue-600',
        red: 'bg-gradient-to-br from-red-400 to-red-600',
        orange: 'bg-gradient-to-br from-yellow-400 to-yellow-600',
        pink: 'bg-gradient-to-br from-pink-400 to-pink-600',
        purple: 'bg-gradient-to-br from-purple-400 to-purple-600',
    };
    return (
        <div className={cn('relative rounded-2xl p-5 text-white overflow-hidden shadow-lg', accentClasses[accent])}>
            <div className="absolute top-4 right-4 h-10 w-10 bg-white/20 rounded-full flex items-center justify-center">{icon}</div>
            <p className="text-sm font-medium text-white/80 uppercase tracking-wider">{title}</p>
            <p className="text-4xl font-bold mt-2">{value}</p>
            {change && <p className="text-sm text-white/80 mt-2">{change}</p>}
        </div>
    );
};

export default function AdminUsers() {
  // --- STATE MANAGEMENT ---
  const [view, setView] = useState('all'); // Main navigation: all, verified, suspended, reports
  const [allUsers, setAllUsers] = useState<Record<string, User>>({});
  const [searchQuery, setSearchQuery] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  // --- DATA FETCHING & PROCESSING ---
  useEffect(() => {
    const usersData = getUsers();
    setAllUsers(usersData || {});
  }, []);

  // Memoize categorized user lists to prevent recalculation on every render
  const { usersList, verifiedUsers, suspendedUsers, pendingUsers, reportUsers } = useMemo(() => {
    const users = Object.values(allUsers);
    return {
      usersList: users,
      verifiedUsers: users.filter(u => u.isApproved && u.status === 'active'),
      suspendedUsers: users.filter(u => u.status === 'suspended'),
      pendingUsers: users.filter(u => !u.isApproved && !u.isRejected && u.status !== 'suspended'),
      reportUsers: users.filter(u => u.isRejected || u.status === 'blocked'), // Example for reports
    };
  }, [allUsers]);

  // This is the core logic to determine what data to show.
  const dataToDisplay = useMemo(() => {
    let baseData;
    switch (view) {
        case 'verified': baseData = verifiedUsers; break;
        case 'suspended': baseData = suspendedUsers; break;
        case 'reports': baseData = reportUsers; break;
        case 'all':
        default:
            baseData = usersList; break;
    }

    // Apply search query on top of the selected data
    if (!searchQuery) return baseData;
    return baseData.filter(u => 
        (u.firstName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
         u.lastName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
         u.email?.toLowerCase().includes(searchQuery.toLowerCase()))
    );
  }, [view, searchQuery, usersList, verifiedUsers, suspendedUsers, pendingUsers, reportUsers]);

  const totalPages = Math.ceil(dataToDisplay.length / itemsPerPage);
  const paginatedData = dataToDisplay.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  // Reset state when the main view changes
  useEffect(() => {
    setCurrentPage(1);
    setSearchQuery('');
  }, [view]);
  
  const getInitials = (firstName: string, lastName: string) => `${(firstName?.[0] || '').toUpperCase()}${(lastName?.[0] || '').toUpperCase()}`;

  // --- DYNAMIC UI RENDER FUNCTIONS ---

  const renderHeaderAndNav = () => {
    const navItems = [
        { id: 'all', label: 'All Users', icon: <UsersIcon size={16}/> },
        { id: 'verified', label: 'Verified', icon: <UserCheck size={16}/> },
        { id: 'suspended', label: 'Suspended', icon: <Ban size={16}/> },
        { id: 'reports', label: 'Reports', icon: <ShieldAlert size={16}/> },
    ];

    const titles = {
      all: { title: 'All Users', desc: 'Manage marketplace travelers, memberships and verification status.' },
      verified: { title: 'Verified Users', desc: 'KYC-approved travelers with completed identity verification.' },
      suspended: { title: 'Suspended Users', desc: 'Accounts temporarily blocked from booking, reviewing or messaging.' },
      reports: { title: 'User Reports', desc: 'Fraud, abuse, and spam reports from users and the system.' },
    };
    const { title, desc } = titles[view];

    return (
        <>
            {/* Top Navigation - Responsive */}
            <nav className="flex flex-wrap items-center gap-2 mb-8">
                {navItems.map(item => (
                    <button key={item.id} onClick={() => setView(item.id)} className={cn("flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all", view === item.id ? "bg-gray-900 text-white shadow-md" : "text-gray-500 bg-white hover:bg-gray-100")}>
                        {item.icon} {item.label}
                    </button>
                ))}
            </nav>
            
            {/* Header - Responsive */}
            <header className="mb-8">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center">
                    <div>
                        <h1 className="text-3xl font-bold text-gray-900">{title}</h1>
                        <p className="mt-1 text-gray-600">{desc}</p>
                    </div>
                    <div className="flex items-center gap-2 mt-4 md:mt-0">
                        {view === 'all' && <Button className="bg-emerald-500 hover:bg-emerald-600 text-white rounded-lg"><UsersRound size={16} className="mr-2"/> Invite User</Button>}
                        <Button variant="outline" className="bg-white rounded-lg"><FileText size={14} className="mr-2"/> Export</Button>
                    </div>
                </div>
            </header>
        </>
    )
  };

  const renderStatCards = () => {
    const commonStats = {
        all: usersList.length,
        verified: verifiedUsers.length,
        suspended: suspendedUsers.length,
        pending: pendingUsers.length,
        reports: reportUsers.length,
    }
    switch(view) {
      case 'verified':
        return <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          <Card title="VERIFIED USERS" value={commonStats.verified} icon={<UserCheck size={20} />} accent="green" />
          <Card title="KYC THIS WEEK" value="412" icon={<Calendar size={20} />} accent="blue" />
          <Card title="AVG APPROVAL TIME" value="1h 12m" icon={<ShieldCheck size={20} />} accent="purple" />
          <Card title="RE-VERIFICATION DUE" value="84" icon={<Clock size={20} />} accent="red" />
        </div>;
      case 'suspended':
        return <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          <Card title="SUSPENDED" value={commonStats.suspended} icon={<Ban size={20} />} accent="red" />
          <Card title="AUTO-SUSPENDED" value="182" icon={<Clock size={20} />} accent="orange" />
          <Card title="PENDING APPEALS" value="27" icon={<FileBadge size={20} />} accent="blue" />
          <Card title="PERMANENTLY BANNED" value="61" icon={<AlertTriangle size={20} />} accent="pink" />
        </div>;
      case 'reports':
        return <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          <Card title="OPEN REPORTS" value={commonStats.reports} icon={<ShieldAlert size={20} />} accent="red" />
          <Card title="INVESTIGATING" value="21" icon={<Shield size={20} />} accent="orange" />
          <Card title="CRITICAL" value="6" icon={<AlertTriangle size={20} />} accent="pink" />
          <Card title="RESOLVED TODAY" value="34" icon={<CheckCircle2 size={20} />} accent="green" />
        </div>;
      case 'all':
      default:
        return <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
            <Card title="TOTAL USERS" value={commonStats.all} icon={<UsersIcon size={20} />} accent="green" />
            <Card title="VERIFIED" value={commonStats.verified} icon={<UserCheck size={20} />} accent="blue" />
            <Card title="SUSPENDED" value={commonStats.suspended} icon={<Ban size={20} />} accent="red" />
            <Card title="PENDING" value={commonStats.pending} icon={<Clock size={20} />} accent="orange" />
        </div>;
    }
  };

  const renderTable = () => {
    const tableHeaders = {
        all: ['User', 'Phone', 'Membership', 'Status'],
        verified: ['User', 'Document', 'Verified On', 'Location', 'Status'],
        suspended: ['User', 'Reason', 'Suspended Date', 'Status'],
        reports: ['Reporter', 'Reported User', 'Reason', 'Severity', 'Date']
    };

    const renderRowContent = (user: User) => {
        const statusBadge = user.status === 'suspended' 
            ? <Badge variant="destructive">Suspended</Badge>
            : user.isApproved 
            ? <Badge className="bg-green-100 text-green-700">Verified</Badge>
            : user.status === 'blocked' || user.isRejected
            ? <Badge variant="destructive">Rejected</Badge>
            : <Badge variant="secondary">Pending</Badge>;

        switch(view) {
            case 'verified':
                return <>
                    <td className="px-6 py-4 text-sm text-gray-600">Driver License</td>
                    <td className="px-6 py-4 text-sm text-gray-600">2025-05-18</td>
                    <td className="px-6 py-4 text-sm text-gray-600">Cusco, PE</td>
                    <td className="px-6 py-4">{statusBadge}</td>
                </>;
            case 'suspended':
                return <>
                    <td className="px-6 py-4 text-sm text-gray-600">Multiple chargebacks</td>
                    <td className="px-6 py-4 text-sm text-gray-600">2026-04-12</td>
                    <td className="px-6 py-4">{statusBadge}</td>
                </>;
            case 'reports':
                return <>
                    <td className="px-6 py-4 text-sm text-gray-800 font-semibold">System</td>
                    <td className="px-6 py-4 text-sm text-gray-600">Spam</td>
                    <td className="px-6 py-4"><Badge variant="outline" className="border-yellow-400 text-yellow-800">Medium</Badge></td>
                    <td className="px-6 py-4 text-sm text-gray-600">2024-07-21</td>
                </>;
            case 'all':
            default:
                return <>
                    <td className="px-6 py-4 text-sm text-gray-600">{user.phone || '+36 193 3053'}</td>
                    <td className="px-6 py-4 text-sm text-gray-600">{user.membership?.planName || 'Summit Elite'}</td>
                    <td className="px-6 py-4">{statusBadge}</td>
                </>;
        }
    }

    return (
        <div className="bg-white rounded-xl shadow-md">
            {/* Toolbar - Responsive */}
            <div className="p-4 flex flex-col md:flex-row justify-end items-center gap-4 border-b border-gray-200">
                <div className="flex items-center gap-2 w-full md:w-auto">
                    <div className="relative w-full md:max-w-xs">
                        <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                        <Input value={searchQuery} onChange={e => setSearchQuery(e.target.value)} placeholder="Search by name or email..." className="pl-9 w-full rounded-lg bg-gray-50" />
                    </div>
                    <Button variant="outline" className="bg-white rounded-lg"><Filter size={14} className="mr-2"/> Filter</Button>
                </div>
            </div>
            {/* Table - Responsive */}
            <div className="overflow-x-auto">
                <table className="w-full text-left min-w-[640px]">
                    <thead>
                        <tr className="text-xs font-semibold text-gray-500 uppercase bg-gray-50">
                            {tableHeaders[view].map(h => <th key={h} className="px-6 py-3">{h}</th>)}
                            <th className="px-6 py-3"></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-200">
                        {paginatedData.map(u => (
                            <tr key={u.email} className="hover:bg-gray-50">
                                <td className="px-6 py-4">
                                    <div className="flex items-center gap-3">
                                        <div className={cn("w-10 h-10 rounded-full text-white flex items-center justify-center font-bold", {'bg-red-500': u.status === 'suspended', 'bg-green-500': u.status === 'active' && u.isApproved, 'bg-gray-400': !u.isApproved && u.status !== 'suspended'})}>{getInitials(u.firstName, u.lastName)}</div>
                                        <div>
                                            <div className="font-bold text-gray-800">{u.firstName} {u.lastName}</div>
                                            <div className="text-sm text-gray-500">{u.email}</div>
                                        </div>
                                    </div>
                                </td>
                                {renderRowContent(u)}
                                <td className="px-6 py-4 text-right">
                                    <DropdownMenu>
                                        <DropdownMenuTrigger asChild><Button variant="ghost" size="icon" className="text-gray-400"><MoreHorizontal size={20} /></Button></DropdownMenuTrigger>
                                        <DropdownMenuContent align="end">
                                            <DropdownMenuItem>View Details</DropdownMenuItem>
                                            {view === 'suspended' && <DropdownMenuItem>Reinstate</DropdownMenuItem>}
                                        </DropdownMenuContent>
                                    </DropdownMenu>
                                </td>
                            </tr>
                        ))}
                         {paginatedData.length === 0 && (<tr><td colSpan={tableHeaders[view].length + 1} className="text-center py-16 text-gray-500">No users found.</td></tr>)}
                    </tbody>
                </table>
            </div>
            {/* Pagination - Responsive */}
            <div className="px-6 py-4 flex flex-col sm:flex-row items-center justify-between gap-4 border-t border-gray-200">
                <span className="text-sm text-gray-500">Showing {paginatedData.length > 0 ? (currentPage - 1) * itemsPerPage + 1 : 0} to {Math.min(currentPage * itemsPerPage, dataToDisplay.length)} of {dataToDisplay.length} users</span>
                <div className="flex items-center gap-1">
                    <Button variant="ghost" size="icon" onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1}><ChevronLeft size={18} /></Button>
                    <span className='text-sm font-semibold'>Page {currentPage} of {totalPages}</span>
                    <Button variant="ghost" size="icon" onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages}><ChevronRight size={18} /></Button>
                </div>
            </div>
        </div>
    );
  }

  return (
    <div className="w-full bg-gray-50/50 min-h-screen p-4 sm:p-6 md:p-8 font-sans">
        <div className="max-w-screen-xl mx-auto">
            {renderHeaderAndNav()}
            {renderStatCards()}
            {renderTable()}
        </div>
    </div>
  );
}